/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const results = [];

    for (const query of queries) {
        const [l, r, k] = query;

        // 1. Identify all even numbers in nums[l..r]
        const removedEvensSet = new Set();
        for (let i = l; i <= r; i++) {
            if (nums[i] % 2 === 0) {
                removedEvensSet.add(nums[i]);
            }
        }

        // 2. Determine the target value.
        // We are looking for the k-th smallest positive even number (2, 4, 6, 8, ...)
        // that is NOT in removedEvensSet.

        // The sequence of all positive even numbers is E = {2n | n >= 1}.
        // The n-th smallest positive even number is 2n.

        // If no numbers are removed, the answer is 2*k.
        // If 'count' numbers are removed, the answer will be 2*(k + count) if the removed numbers were all less than the target,
        // but this is complicated because the removed numbers can be anywhere.

        // A more direct approach:
        // We are looking for the smallest integer X such that:
        // 1. X is a positive even number (X = 2n).
        // 2. X is not in removedEvensSet.
        // 3. The count of even numbers smaller than or equal to X AND not in removedEvensSet is exactly k.

        // Let E(X) be the set of even numbers <= X. |E(X)| = floor(X/2).
        // Let R_X = {e in removedEvensSet | e <= X}.
        // The count of remaining even numbers <= X is |E(X)| - |R_X|.
        // We need to find the smallest even X such that |E(X)| - |R_X| >= k,
        // and for X' = X-2, |E(X')| - |R_{X'}| < k. (If X > 2)

        // Since the target X must be even, let X = 2n.
        // We want the smallest n such that:
        // floor(2n/2) - |{e in removedEvensSet | e <= 2n}| >= k
        // n - |{e in removedEvensSet | e <= 2n}| >= k

        // Let f(n) = n - |{e in removedEvensSet | e <= 2n}|. We seek the smallest n such that f(n) >= k.

        // The function f(n) is monotonically non-decreasing with n. We can use binary search on n.

        // Range for n:
        // The smallest possible answer is 2 (n=1).
        // The largest possible answer? k is up to 10^9. If no evens are removed, the answer is 2*10^9.
        // A safe upper bound for 2n is 2 * (10^9 + |removedEvensSet|).
        // Max |removedEvensSet| <= nums.length <= 10^5.
        // Max n ~ 10^9 + 10^5. Let's use 2 * 10^9 + 10^5 as a safe upper bound for X, so N_max ~ 10^9 + 5 * 10^4.

        let low_n = 1;
        // Upper bound estimate for n: k + number of removed evens.
        let high_n = k + removedEvensSet.size + 2; 

        // Since k <= 10^9 and size <= 10^5, high_n is around 10^9.
        // A tighter bound on X would be 2 * (k + nums.length).
        // Let's set a practical upper limit to avoid overflow if k was much larger, 
        // but given k <= 10^9, high_n is fine.
        high_n = Math.max(high_n, 2 * 10**9); 

        let best_n = high_n;

        while (low_n <= high_n) {
            const mid_n = Math.floor((low_n + high_n) / 2);
            const X = 2 * mid_n;

            // Calculate |{e in removedEvensSet | e <= X}|
            let removedCount = 0;
            for (const e of removedEvensSet) {
                if (e <= X) {
                    removedCount++;
                }
            }

            // f(mid_n) = mid_n - removedCount
            const currentCount = mid_n - removedCount;

            if (currentCount >= k) {
                // mid_n might be the answer, try for a smaller n
                best_n = mid_n;
                high_n = mid_n - 1;
            } else {
                // mid_n is too small, need a larger n
                low_n = mid_n + 1;
            }
        }

        // The result is 2 * best_n
        results.push(2 * best_n);
    }

    return results;
}

